from kafka import KafkaConsumer
import json
import pickle
from typing import Dict, Any, Callable
import logging

class FinancialTransactionConsumer:
    def __init__(self, bootstrap_servers: str, group_id: str):
        self.consumer = KafkaConsumer(
            bootstrap_servers=bootstrap_servers,
            group_id=group_id,
            value_deserializer=self._deserialize_message,
            auto_offset_reset='earliest',
            enable_auto_commit=True
        )
        self.message_handlers: Dict[str, Callable] = {}
        self.logger = logging.getLogger(__name__)
    
    def _deserialize_message(self, value: bytes) -> Dict[str, Any]:
        try:
            return json.loads(value.decode('utf-8'))
        except:
            try:
                return pickle.loads(value)
            except:
                return value
    
    def register_handler(self, message_type: str, handler: Callable):
        self.message_handlers[message_type] = handler
    
    def process_message(self, message: Any):
        try:
            message_type = message.get('type')
            if message_type and message_type in self.message_handlers:
                handler = self.message_handlers[message_type]
                handler(message)
            else:
                self.logger.warning(f"No handler found for message type: {message_type}")
        except Exception as e:
            self.logger.error(f"Error processing message: {str(e)}")
    
    def start_consuming(self, topics: list):
        self.consumer.subscribe(topics)
        self.logger.info(f"Started consuming from topics: {topics}")
        
        try:
            for message in self.consumer:
                self.process_message(message.value)
        except KeyboardInterrupt:
            self.logger.info("Consumer stopped by user")
        except Exception as e:
            self.logger.error(f"Consumer error: {str(e)}")
        finally:
            self.consumer.close()

# Example usage
def process_payment_transaction(transaction):
    print(f"Processing payment: {transaction['transaction_id']} for amount {transaction['amount']}")

def process_refund_transaction(transaction):
    print(f"Processing refund: {transaction['transaction_id']} for amount {transaction['amount']}")

# Create consumer instance
consumer = FinancialTransactionConsumer(
    bootstrap_servers='localhost:9092',
    group_id='financial-group'
)

# Register handlers
consumer.register_handler('payment', process_payment_transaction)
consumer.register_handler('refund', process_refund_transaction)

# Start consuming
consumer.start_consuming(['transactions'])